#!/usr/bin/env python3
"""
Stage 6 Frontend: Portfolio Analytics page + Sidebar + i18n
Run from C:\\ai-capitalS-mvp:  python3 deploy_stage6_frontend.py
"""
import base64, os, sys

ROOT = r"C:\ai-capitalS-mvp"
if os.name != "nt":
    ROOT = os.getcwd()

# ─── 1. Portfolio Analytics page.tsx ───
PAGE_B64 = ""

page_dir = os.path.join(ROOT, "frontend", "app", "portfolio-analytics")
os.makedirs(page_dir, exist_ok=True)
page_path = os.path.join(page_dir, "page.tsx")
with open(page_path, "wb") as f:
    f.write(base64.b64decode(PAGE_B64))
print(f"[OK] {page_path} ({os.path.getsize(page_path)} bytes)")

# ─── 2. Update Sidebar.tsx ───
sidebar_path = os.path.join(ROOT, "frontend", "components", "Sidebar.tsx")
if os.path.exists(sidebar_path):
    with open(sidebar_path, "r", encoding="utf-8") as f:
        sidebar = f.read()
    if "portfolio-analytics" in sidebar:
        print("[SKIP] Sidebar already has portfolio-analytics")
    else:
        new_item = '      { labelKey: \'portfolioAnalytics\', path: \'/portfolio-analytics\',\n        icon: <Icon paths={<><rect x="3" y="3" width="18" height="18" rx="2"/><path d="M7 17V13"/><path d="M12 17V9"/><path d="M17 17V5"/></>} /> },'
        target = "      { labelKey: 'stressTest',"
        if target in sidebar:
            sidebar = sidebar.replace(target, new_item + "\n" + target)
            with open(sidebar_path, "w", encoding="utf-8") as f:
                f.write(sidebar)
            print("[OK] Sidebar updated with portfolioAnalytics")
        else:
            print("[WARN] Could not find stressTest in Sidebar")
else:
    print(f"[WARN] Sidebar not found at {sidebar_path}")

# ─── 3. Update locale files ───
locale_data = {
    "ru": ("\u041f\u043e\u0440\u0442\u0444\u0435\u043b\u044c\u043d\u0430\u044f \u0430\u043d\u0430\u043b\u0438\u0442\u0438\u043a\u0430", "ru.ts"),
    "en": ("Portfolio Analytics", "en.ts"),
    "uz": ("Portfel tahlili", "uz.ts"),
}
for lang, (label, fname) in locale_data.items():
    path = os.path.join(ROOT, "frontend", "lib", "locales", fname)
    if not os.path.exists(path):
        print(f"[WARN] {fname} not found")
        continue
    with open(path, "r", encoding="utf-8") as f:
        content = f.read()
    if "portfolioAnalytics" in content:
        print(f"[SKIP] {fname} already has portfolioAnalytics")
        continue
    if "stressTest:" in content:
        content = content.replace('stressTest:', f"portfolioAnalytics: '{label}',\n      stressTest:")
        with open(path, "w", encoding="utf-8") as f:
            f.write(content)
        print(f"[OK] {fname} updated")
    else:
        print(f"[WARN] Cannot update {fname} — stressTest key not found")

print()
print("=== Stage 6 Frontend deployed ===")
print("Rebuild: docker compose build frontend && docker compose up -d")
